logic [3:0] a;
logic [3:0] q;
assign q = 4'd1 / a; // when a==0, q must be 4'bx

logic [3:0] exp_v;
logic [3:0] result;
assign exp_v = 4'bx;
assign result = 4'd2 ** exp_v; // result must be 4'bx

input [3:0] a;
output [3:0] y;
assign y = 4'd2 ** (4'd1 / a); // when a==0: inner div yields x, y must be 4'bx
